// Scope — Datamosh Drift
// AI feed with heavy feedback, slow organic warp, datamosh aesthetic

scope.prompt('datamosh, shards from I-frame deletion, dense horizontal motion vector tear pattern, glitch art')
  .noise(0.12)
  .step1(950)
  .step2(700)
  .step3(420)

AUDIO.bins = 4; AUDIO.smooth = 0.90; AUDIO.apply();
var low = env(() => a.fft[0] || 0, 0.3, 0.05);
var mid = env(() => a.fft[1] || 0, 0.3, 0.06);

speed = 0.4

const rampMask = () => Math.min(1, time * 0.8)

// Scope NDI feed — s3 is auto-initialized
src(s3)
  .saturate(0.8)
  .contrast(1.1)
  .out(o1)

// feedback painting from the AI feed
src(o1)
  .modulate(noise(1.5, 0.02), () => 0.015 + mid() * 0.005)
  .modulateScale(noise(0.8, 0.01), 0.005)
  .color(
    () => 0.9 + low() * 0.08,
    () => 0.85 + mid() * 0.05,
    () => 1.0
  )
  .saturate(() => 1.1 + low() * 0.03)
  .blend(src(o0).scale(1.001).rotate(() => Math.sin(time * 0.02) * 0.001), () => rampMask() * 0.82)
  .colorama(() => 0.002 + mid() * 0.0008)
  .out(o0)
